INSERT INTO faqs (question, answer, is_active, display_order) VALUES
(N'What documents do I need to rent a vehicle?', N'You need a valid driver license (and matching CCCD/Passport). Our system will automatically verify your license during onboarding.', 1, 1),
(N'How does the deposit system work?', N'A security deposit is required before picking up the vehicle. This is held to cover toll fees, minor damages, or late return fees, and will be refunded within 3 days after returning the vehicle.', 1, 2),
(N'Can I cancel my booking?', N'Yes, you can cancel your booking for free up to 24 hours before the rental starts. Late cancellations may incur a 1-day rental fee charge.', 1, 3),
(N'Is insurance included?', N'Standard liability insurance is included with all vehicle rentals. Premium damage waivers can be purchased during checkout.', 1, 4);
